final:
module up_counter (
    input clk,
    input load,
    input [3:0] load_value,
    output reg [3:0] count
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (load) begin
            count <= load_value;
        end else begin
            count <= count + 1;
        end
    end

endmodule
